                if best is None or d2 < best:
                    best = d2
                    best_move = (dx, dy)
            return [best_move[0], best_move[1]]

    if (ox, oy) != (sx, sy):
        best = None
        best_mv = (0, 0)
        for dx, dy, nx, ny in legal:
            d = manh(nx, ny, ox, oy)
            if best is None or d < best:
                best = d
                best_mv = (dx, dy)
        return [best_mv[0], best_mv[1]]

    return [0, 0]
